sql:
SELECT COUNT(*) AS advanced_templates_count
FROM configuration_templates
WHERE version > 1;

SELECT *
FROM env_configurations
WHERE config_id = 1;

SELECT category, SUM(optional) AS num_optional
FROM config_parameters
GROUP BY category;

SELECT count(*)
FROM env_configurations
WHERE env_id = 1;

SELECT param_id, env_id, value
FROM env_configurations
WHERE value > 200;

SELECT * 
FROM users
WHERE user_name IN (SELECT param_name FROM config_parameters);

SELECT DISTINCT cp.param_name
FROM config_parameters cp
WHERE cp.category = 'Config & Admin' AND cp.param_is_sensitive = 1;

SELECT param_name 
FROM config_parameters 
WHERE param_id IN (0, 1);

